parameters.jsCode:
// Collapse the per-category rows into one summary item: each category's
// share of total revenue AND share of total orders (so a category with a
// revenue share well above its order share = unusually high average order
// value, and vice versa — that divergence is what "surprisingly high/low
// revenue share" means downstream, not revenue share in isolation).
const rows = $input.all().map(item => item.json);

const totalRevenue = rows.reduce((sum, r) => sum + Number(r.revenue), 0);
const totalOrders = rows.reduce((sum, r) => sum + Number(r.orders), 0);

const categories = rows
  .map(r => {
    const revenue = Number(r.revenue);
    const orders = Number(r.orders);
    return {
      // dim_product.category is NULL for ~1-2% of products (no category
      // assigned in the source data) — label it rather than emit `null`
      // into the prompt.
      category: r.category === null ? 'Uncategorized' : r.category,
      orders,
      revenue: Math.round(revenue * 100) / 100,
      revenue_share_pct: totalRevenue > 0 ? Math.round((revenue / totalRevenue) * 10000) / 100 : 0,
      orders_share_pct: totalOrders > 0 ? Math.round((orders / totalOrders) * 10000) / 100 : 0,
    };
  })
  .sort((a, b) => b.revenue - a.revenue);

return [{
  json: {
    total_revenue: Math.round(totalRevenue * 100) / 100,
    total_orders: totalOrders,
    category_count: categories.length,
    categories,
  },
}];

