={
  "model": "llama3.2",
  "prompt": "Here is a revenue breakdown by product category from an e-commerce warehouse, sorted by revenue descending. Each category shows its share of total revenue and share of total orders: {{ JSON.stringify($json.categories) }}. Total revenue: {{ $json.total_revenue }}, total orders: {{ $json.total_orders }}. Write a 3-sentence narrative highlighting (1) the top category by revenue, and (2) any category whose revenue share is surprisingly high or low relative to its order share (i.e. unusually high or low average order value for that category).",
  "stream": false
}
